CREATE TABLE `mgma_measurements` (
	`id` TEXT PRIMARY KEY NOT NULL,
	`kpi_id` TEXT NOT NULL,
	`scope_type` TEXT NOT NULL CHECK (`scope_type` IN ('profit_center', 'corporate_office')),
	`scope_id` TEXT NOT NULL CHECK (`scope_id` IN ('EO', 'GAD', 'GRO', 'BHC')),
	`evidence_class` TEXT NOT NULL CHECK (`evidence_class` IN ('synthetic_demo', 'production')),
	`period_start` TEXT NOT NULL,
	`period_end` TEXT NOT NULL,
	`numerator_value` TEXT,
	`denominator_value` TEXT,
	`calculated_value` TEXT NOT NULL,
	`source_reference` TEXT NOT NULL,
	`source_record_ids_json` TEXT NOT NULL DEFAULT '[]',
	`source_record_count` INTEGER NOT NULL DEFAULT 0,
	`collected_at` TEXT NOT NULL,
	`created_at` TEXT NOT NULL,
	FOREIGN KEY (`kpi_id`) REFERENCES `mgma_kpi_targets`(`id`) ON DELETE RESTRICT
);
--> statement-breakpoint
CREATE UNIQUE INDEX `idx_mgma_measurement_period_scope` ON `mgma_measurements` (`kpi_id`, `scope_id`, `evidence_class`, `period_start`, `period_end`);
--> statement-breakpoint
CREATE INDEX `idx_mgma_measurement_mode_scope` ON `mgma_measurements` (`evidence_class`, `scope_type`, `scope_id`);
--> statement-breakpoint

CREATE TABLE `mgma_data_quality_results` (
	`id` TEXT PRIMARY KEY NOT NULL,
	`measurement_id` TEXT,
	`kpi_id` TEXT NOT NULL,
	`scope_id` TEXT NOT NULL CHECK (`scope_id` IN ('EO', 'GAD', 'GRO', 'BHC')),
	`evidence_class` TEXT NOT NULL CHECK (`evidence_class` IN ('synthetic_demo', 'production')),
	`check_type` TEXT NOT NULL CHECK (`check_type` IN ('completeness', 'timeliness', 'duplication', 'denominator_validity', 'stale_data')),
	`check_status` TEXT NOT NULL CHECK (`check_status` IN ('pass', 'fail', 'not_run')),
	`reason_code` TEXT NOT NULL,
	`details` TEXT NOT NULL,
	`evaluated_at` TEXT NOT NULL,
	FOREIGN KEY (`measurement_id`) REFERENCES `mgma_measurements`(`id`) ON DELETE CASCADE,
	FOREIGN KEY (`kpi_id`) REFERENCES `mgma_kpi_targets`(`id`) ON DELETE RESTRICT
);
--> statement-breakpoint
CREATE INDEX `idx_mgma_dq_mode_scope` ON `mgma_data_quality_results` (`evidence_class`, `scope_id`, `check_type`, `check_status`);
--> statement-breakpoint

CREATE TABLE `mgma_dashboard_governance` (
	`id` TEXT PRIMARY KEY NOT NULL,
	`baseline_period_start` TEXT NOT NULL,
	`baseline_period_end` TEXT NOT NULL,
	`dashboard_cadence` TEXT NOT NULL CHECK (`dashboard_cadence` IN ('monthly', 'quarterly')),
	`close_rule` TEXT NOT NULL,
	`status` TEXT NOT NULL CHECK (`status` IN ('prototype-reviewed', 'pending-owner-acceptance', 'owner-approved')),
	`owner_role` TEXT NOT NULL,
	`reviewer_label` TEXT NOT NULL,
	`review_class` TEXT NOT NULL CHECK (`review_class` IN ('synthetic_prototype', 'human')),
	`reviewed_at` TEXT NOT NULL,
	`note` TEXT NOT NULL
);
--> statement-breakpoint

CREATE TABLE `mgma_owner_approvals` (
	`id` TEXT PRIMARY KEY NOT NULL,
	`kpi_id` TEXT NOT NULL,
	`owner_role` TEXT NOT NULL,
	`formula_status` TEXT NOT NULL,
	`target_status` TEXT NOT NULL,
	`source_status` TEXT NOT NULL,
	`cadence_status` TEXT NOT NULL,
	`reviewer_label` TEXT NOT NULL,
	`review_class` TEXT NOT NULL CHECK (`review_class` IN ('synthetic_prototype', 'human')),
	`reviewed_at` TEXT NOT NULL,
	`note` TEXT NOT NULL,
	FOREIGN KEY (`kpi_id`) REFERENCES `mgma_kpi_targets`(`id`) ON DELETE CASCADE
);
--> statement-breakpoint
CREATE UNIQUE INDEX `idx_mgma_owner_approval_kpi` ON `mgma_owner_approvals` (`kpi_id`);
