UPDATE mgma_kpi_targets SET domain_id='M13-D2', kpi_description='Estimated days required to convert ending gross accounts receivable into cash at the period''s average daily gross-charge rate.', target_value='40', target_unit='days', comparison_operator='less_than_or_equal', benchmark_source='AMOS M1.3 internal prototype target', formula='ending gross accounts receivable / average daily gross charges', numerator_definition='Unpaid gross claim balance at fixed-period end.', denominator_definition='Gross charges in the fixed period divided by calendar days in that period.', source_system='AMOS-OPS Revenue Cycle', source_fields_json='["claims.outstanding_balance","claims.service_date","claims.gross_charge","payments.posted_at"]', owner_role='Revenue Cycle Manager', drill_down_path='/revenue/aging?kpi=001', target_basis='Internal evaluation threshold; neither externally benchmarked nor survey-derived and carrying no third-party authority.', target_approval_status='prototype-reviewed', stale_after_hours=768, scope_ids_json='["BHC","GRO","EO"]', is_checklist_target=1, measurement_frequency='monthly', alert_threshold='45' WHERE id='M13-KPI-001';
