INSERT INTO `mgma_data_quality_results`
(`id`,`measurement_id`,`kpi_id`,`scope_id`,`evidence_class`,`check_type`,`check_status`,`reason_code`,`details`,`evaluated_at`)
SELECT m.`id` || '-' || c.`suffix`, m.`id`, m.`kpi_id`, m.`scope_id`, m.`evidence_class`,
       c.`check_type`, 'pass', c.`reason_code`, c.`details`, '2026-07-01T12:00:00Z'
FROM `mgma_measurements` m
CROSS JOIN (
  SELECT 'COMP' AS `suffix`, 'completeness' AS `check_type`, 'M13-DQ-COMPLETE' AS `reason_code`, 'All required synthetic demonstration fields are present.' AS `details`
  UNION ALL SELECT 'TIME','timeliness','M13-DQ-TIMELY','The synthetic demonstration measurement was collected within its controlled refresh window.'
  UNION ALL SELECT 'DUP','duplication','M13-DQ-UNIQUE','No duplicate synthetic source identifiers were detected.'
  UNION ALL SELECT 'DEN','denominator_validity','M13-DQ-DENOMINATOR-VALID','The denominator is present and greater than zero.'
  UNION ALL SELECT 'STALE','stale_data','M13-DQ-CURRENT','The synthetic demonstration measurement is not stale at the fixed evaluation time.'
) c;
